where id = #{id, jdbcType=BINARY}

mapper.update:
update post_media_asset
set upload_status = 'COMPLETING',
    upload_operation_version = upload_operation_version + 1,
    upload_updated_at = #{updateTime},
    failure_reason = '',
    update_time = #{updateTime}
where id = #{id, jdbcType=BINARY}
  and owner_user_id = #{actorUserId, jdbcType=BINARY}
  and lifecycle = 'DRAFT'
  and upload_status = 'PREPARED'
  and upload_operation_version = #{operationVersion}

update post_media_asset
set lifecycle = 'UPLOADED',
    upload_status = 'COMPLETED',
    upload_updated_at = #{updateTime},
    failure_reason = '',
    update_time = #{updateTime}
where id = #{id, jdbcType=BINARY}
  and upload_status = 'OBJECT_COMPLETED'
  and upload_operation_version = #{operationVersion}

update post_media_asset
set upload_status = 'FAILED',
    upload_updated_at = #{updateTime},
    failure_reason = #{failureReason},
    update_time = #{updateTime}
where id = #{id, jdbcType=BINARY}
  and upload_status in ('COMPLETING', 'OBJECT_COMPLETED')
  and upload_operation_version = #{operationVersion}

update post_media_asset
set upload_status = 'PREPARED',
    upload_operation_version = upload_operation_version + 1,
    upload_updated_at = #{resetAt},
    failure_reason = '',
    update_time = #{resetAt}
where id = #{id, jdbcType=BINARY}
  and lifecycle = 'DRAFT'
  and upload_status = 'COMPLETING'
  and upload_operation_version = #{operationVersion}
  and upload_updated_at <= #{staleBefore}

update post_media_asset
set upload_updated_at = #{updateTime},
    failure_reason = #{failureReason}
where id = #{id, jdbcType=BINARY}
  and lifecycle = 'DRAFT'
  and upload_status in ('COMPLETING', 'OBJECT_COMPLETED')
  and upload_operation_version = #{operationVersion}
  and upload_updated_at <= #{staleBefore}

mapper.select:
select 
from post_media_asset
where upload_status in ('COMPLETING', 'OBJECT_COMPLETED')
  and upload_updated_at <= #{updatedBefore}
order by upload_updated_at asc, id asc
limit #{limit}

