update post_media_asset
set lifecycle = 'BOUND',
    reference_status = 'BOUND',
    reference_updated_at = #{updateTime},
    update_time = #{updateTime}
where id = #{id, jdbcType=BINARY}
  and reference_status = 'BIND_PENDING'
  and reference_operation_version = #{operationVersion}

update post_media_asset
set lifecycle = 'RELEASED',
    reference_status = 'RELEASED',
    reference_updated_at = #{updateTime},
    update_time = #{updateTime}
where id = #{id, jdbcType=BINARY}
  and reference_status = 'RELEASE_PENDING'
  and reference_operation_version = #{operationVersion}

mapper.select:
select 
from post_media_asset
where id > #{afterAssetId, jdbcType=BINARY}
  and reference_status in ('BIND_PENDING', 'BOUND', 'RELEASE_PENDING', 'RELEASED')
order by id asc
limit #{limit}
